import{_ as a,o as t,c as o,ae as i}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"Facebook Traffic and Conversion Ads","description":"","frontmatter":{"title":"Facebook Traffic and Conversion Ads","slug":"facebook-traffic-and-conversion-ads"},"headers":[],"relativePath":"marketer-hub/facebook-traffic-and-conversion-ads.md","filePath":"marketer-hub/facebook-traffic-and-conversion-ads.md"}'),n={name:"marketer-hub/facebook-traffic-and-conversion-ads.md"};function r(s,e,l,c,d,p){return t(),o("div",null,[...e[0]||(e[0]=[i('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Branch Links can be used together with Facebook Traffic and Conversion ads, allowing you to track engagement with your advertisements and ad-driven installs which deep link new users directly to content the first time they open your app.</p><p>Note: This documentation applies for Ad placements across Facebook and the Audience Network.</p><p>This documentation supports the following Facebook Ad Campaign types:</p><table tabindex="0"><thead><tr><th>Facebook Campaign Category</th><th>Campaign Type/Objective</th><th>Branch Ad Format</th></tr></thead><tbody><tr><td>Consideration</td><td>Traffic</td><td>Cross-platform Display</td></tr><tr><td>Conversion</td><td>Conversions</td><td>Cross-platform Display</td></tr></tbody></table><h5 id="facebook-campaign-advert-format-support-table" tabindex="-1">Facebook Campaign Advert Format Support Table <a class="header-anchor" href="#facebook-campaign-advert-format-support-table" aria-label="Permalink to &quot;Facebook Campaign Advert Format Support Table&quot;">​</a></h5><table tabindex="0"><thead><tr><th>Facebook Campaign Type</th><th>Photo</th><th>Video</th><th>Carousel</th><th>Slideshow</th><th>Collection</th><th>Dynamic</th><th>Canvas</th></tr></thead><tbody><tr><td>Traffic</td><td>✔︎</td><td>✔︎</td><td>✔︎</td><td>✔︎</td><td>✔︎</td><td>✔︎</td><td>✔︎</td></tr><tr><td>Conversion</td><td>✔︎</td><td>✔︎</td><td>✔︎</td><td>✔︎</td><td></td><td></td><td>✔︎</td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">Facebook Campaign Types</p><p>Looking for other Facebook Ad campaign types? Please check out our <a href="./facebook-ads-overview.html">Facebook Ads Overview guide</a>.</p></div><h2 id="setup" tabindex="-1">Setup <a class="header-anchor" href="#setup" aria-label="Permalink to &quot;Setup&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">Prerequisites</p><ul><li><p>To track installs from Facebook Ads you should <a href="./native-sdks-overview.html">integrate the Branch SDK</a> into your app.</p></li><li><p>To use Branch Links in Facebook App Install Ads ensure you have:</p><ul><li>URI schemes configured on iOS</li><li>URI schemes configured on Android</li><li>iOS App Store ID set</li><li>Android Package Name set</li><li>Social Media Settings filled out (i.e. OG tags at the bottom of <a href="./configure-default-link-behaviors.html#4-social-media-preview">Link Settings</a></li></ul></li><li><p>If you want to deep link from your ads directly to content, you should <a href="./in-app-routing.html">configure deep link routing</a>.</p></li><li><p>Ads is a premium product priced on Monthly Active Users. Sign up for the Ads product to enable this functionality.&quot;</p></li></ul></div><h5 id="enable-facebook-as-an-ad-partner-for-measurement" tabindex="-1">Enable Facebook as an Ad Partner (for measurement) <a class="header-anchor" href="#enable-facebook-as-an-ad-partner-for-measurement" aria-label="Permalink to &quot;Enable Facebook as an Ad Partner (for measurement)&quot;">​</a></h5><div class="info custom-block"><p class="custom-block-title">Enable Facebook as an Ad Partner</p><p>Completing this section -- <strong>Enable Facebook as an Ad Partner</strong> -- will result in Branch sending app events to Facebook in order to attribute them back to ad campaigns. <strong>This does not enable deep linking for the ad</strong>. Further work below is required for deep linking.</p></div><p>If you haven&#39;t enabled Facebook as an Ad Partner on the Branch dashboard follow this section to do so. Advanced options for sending events can be found <a href="./facebook-mmp-event-options.html">here</a>.</p><ol><li>Navigate to the <a href="https://dashboard.branch.io/ads/partner-management" target="_blank" rel="noreferrer">Partner Management tab</a>.</li></ol><p><em>[Image: 2770]</em></p><ol start="2"><li>Search for <strong>Facebook</strong>.</li><li>Click <strong>Connect With Facebook</strong></li></ol><p><em>[Image: 1141]</em></p><ol start="4"><li>Log in to Facebook if you are not logged in</li></ol><p><em>[Image: 587]</em></p><ol start="5"><li>Confirm that Branch can receive your public profile</li></ol><p><em>[Image: 712]</em></p><ol start="6"><li>Confirm that Branch can have permissions <code>ads_read</code></li></ol><p><em>[Image: 712]</em></p><p><code>ads_read</code> is used to surface impressions and clicks on the Branch Dashboard.</p><ol start="7"><li>Select the ad accounts for which you want to run app install ads or app engagement ads</li></ol><p><em>[Image: 1137]</em></p><div class="info custom-block"><p class="custom-block-title">Ad Account FAQ</p><p>If you are having trouble finding or selecting the ad account(s) for which you want to run ads, please visit our <a href="./i-cant-see-the-ad-account-i-want-to-use-at-all.html">FAQ</a>.</p></div><ol start="8"><li>Click to select a Facebook app id for which you want to run Facebook ads</li></ol><p><em>[Image: 1136]</em></p><ol start="9"><li>Copy the app id</li></ol><p><em>[Image: 1172]</em></p><ol start="10"><li>Paste the app id and press <code>Save</code></li></ol><p><em>[Image: 1182]</em></p><ol start="11"><li><p>Facebook is now enabled as an ad partner!</p><p>Note that if you have different attribution windows between Facebook and Branch, those will be highlighted. The warning has a link to the docs on how to align these attribution windows.</p></li></ol><p><em>[Image: 487]</em></p><ol start="12"><li>Finally, to create a Facebook Ads link click the <strong>Create Facebook Link</strong> button in the top right hand corner.</li></ol><p><em>[Image: 2882]</em></p><h2 id="create-an-ad-link" tabindex="-1">Create an Ad Link <a class="header-anchor" href="#create-an-ad-link" aria-label="Permalink to &quot;Create an Ad Link&quot;">​</a></h2><div class="info custom-block"><p class="custom-block-title">Optional if Running App-Only Ads</p><p>This section is optional if you are running app-only ads. We will automatically pull in campaign, ad set, ad, and creative information from Facebook. However, if you want users to be deep linked, you should follow the instructions in this section.</p></div><ol><li>Create a Branch Ad link from the <a href="https://dashboard.branch.io/ads/partner-management" target="_blank" rel="noreferrer">Partner Management page</a> <code>Create Facebook Link</code> button under the Facebook Partner and select <code>Create Display Link</code>.</li></ol><p><em>[Image: 1306]</em></p><ol start="2"><li>Under the Define Section, pick a Link Name for later reference.</li><li>Configure the link with the Ad Partner set to <strong>Facebook</strong>, and the Ad Format set to <strong>Cross-platform Display</strong>.</li></ol><p><em>[Image: 2350]</em></p><ol start="4"><li>Under the Configure Options tab, navigate to the Redirects sub section and ensure that the iOS/Android and Desktop redirects are set to the desired destinations being promoted by the ad campaign.</li></ol><p><em>[Image: 1920]</em></p><ol start="5"><li>Under the Analytics Tags sub-section additional tags can be set. It is recommended to fill in these fields as they can be used as filters in Branch&#39;s Ads Analytics view. To best connect your ad link with your Facebook Campaign, set the channel field to Facebook Ads and set the campaign field to the same ad campaign name used in Facebook Ads.</li></ol><p><em>[Image: 2242]</em></p><div class="warning custom-block"><p class="custom-block-title">Disabling Deepviews</p><p>In order for your campaign to run effectively, be sure to disable Deepviews. You can either <a href="./deepviews.html">disable Deepviews</a> for your entire account or <a href="./advanced-deepview-configurations.html#disable-per-link-deepviews">disable Deepviews for one link</a>.</p></div><div class="info custom-block"><p class="custom-block-title">Optional: Deep Link Data</p><p>You can use this configuration section to specify custom link parameters that will be deep linked into the app after install. These could include a coupon code or a page identifier to route the user. Visit the <a href="./in-app-routing.html">Deep Link Routing</a> page to learn more.</p></div><h3 id="traffic-campaign-setup" tabindex="-1">Traffic Campaign Setup <a class="header-anchor" href="#traffic-campaign-setup" aria-label="Permalink to &quot;Traffic Campaign Setup&quot;">​</a></h3><h5 id="configure-an-ad" tabindex="-1">Configure an Ad <a class="header-anchor" href="#configure-an-ad" aria-label="Permalink to &quot;Configure an Ad&quot;">​</a></h5><p>To set up a Facebook Traffic campaign, you will need to first create your campaign and use a Branch link as the Deep Link URL for the advertisements. Facebook Traffic Campaign information is available <a href="https://www.facebook.com/business/ads-guide/traffic" target="_blank" rel="noreferrer"><strong>here</strong></a>.</p><h5 id="create-your-campaign" tabindex="-1">Create Your Campaign <a class="header-anchor" href="#create-your-campaign" aria-label="Permalink to &quot;Create Your Campaign&quot;">​</a></h5><ol><li>Navigate to <a href="https://www.facebook.com/ads/create" target="_blank" rel="noreferrer">https://www.facebook.com/ads/create</a> while logged in to the account that owns your Facebook app.</li><li>Select <strong>Traffic</strong> as the campaign marketing objective.</li></ol><p><em>[Image: 1926]</em></p><ol start="3"><li>Select either to drive traffic to your <code>Website</code> or your <code>App</code></li><li>Continue with campaign creation selecting the app to advertise, audience, placement, and budget. Then press continue to enter the Advert creation step.</li><li>Now select an advertisement format and customize your ad</li><li>Add your Branch Ad Link to your advertisement</li></ol><ul><li>If you chose to drive traffic to an App, locate the <strong>Deep Link</strong> field and copy and paste your Branch link there.</li></ul><p><em>[Image: 1894]</em></p><ul><li>If you chose to drive traffic to a Website, paste your Branch Ad link into the <strong>Website URL</strong> field.</li></ul><p><em>[Image: 1914]</em></p><ul><li>If you chose to drive traffic to a Website and are using a full-screen Canvas, add your Branch Ad link as the <strong>Destination URL</strong> for your canvas advertisement components.</li></ul><ol start="7"><li>Complete the rest of the ad campaign setup.</li></ol><div class="info custom-block"><p class="custom-block-title">Optional: Ad formats with Multiple Links</p><div class="info custom-block"><p class="custom-block-title">Optional: Ad formats with Multiple Links</p><p>Some ad formats such as Carousel format can handle multiple deep links. To have link performance data on each image or component of the advertisement, create multiple Branch Ad links to be used in each part of the multiple link advertisement format. This format is useful if you want to drive customers to different content pieces or products.</p></div></div><p>:::</p><h3 id="conversions-campaign-setup" tabindex="-1">Conversions Campaign Setup <a class="header-anchor" href="#conversions-campaign-setup" aria-label="Permalink to &quot;Conversions Campaign Setup&quot;">​</a></h3><h5 id="configure-an-ad-1" tabindex="-1">Configure an Ad <a class="header-anchor" href="#configure-an-ad-1" aria-label="Permalink to &quot;Configure an Ad&quot;">​</a></h5><p>To set up a Facebook Conversions campaign, you will need to first create your campaign and use a Branch link as the Deep Link URL for the advertisements. Facebook Conversions Campaign information is available <a href="https://www.facebook.com/business/ads-guide/conversions" target="_blank" rel="noreferrer"><strong>here</strong></a>.</p><div class="warning custom-block"><p class="custom-block-title">Prerequisites</p><p>As a prerequisite, Facebook requires you to report events about your users interacting with your content, for example: viewing, adding to cart, and purchasing. To add the Facebook Pixel to your website, and event tracking using the Branch SDK (which forwards to Facebook) to your app, follow these instructions:</p></div><ul><li><a href="./tracking-other-conversion-events-with-facebook.html">Sending App Events with the Branch SDK</a></li><li><a href="https://developers.facebook.com/docs/marketing-api/facebook-pixel/v2.8" target="_blank" rel="noreferrer">Sending Web Events with the Facebook Pixel</a></li></ul><h5 id="create-your-campaign-1" tabindex="-1">Create Your Campaign <a class="header-anchor" href="#create-your-campaign-1" aria-label="Permalink to &quot;Create Your Campaign&quot;">​</a></h5><ol><li>Navigate to <a href="https://www.facebook.com/ads/create" target="_blank" rel="noreferrer">https://www.facebook.com/ads/create</a> while logged in to the account that owns your Facebook app.</li><li>Select <strong>Conversions</strong> as the campaign marketing objective.</li></ol><p><em>[Image: 1926]</em></p><ol start="3"><li>Select either to have the goal of having conversions on a <code>Website</code> or in an <code>App</code></li><li>Continue with campaign creation selecting an audience, placement, and budget. Then press continue to enter the Advert creation step.</li><li>Now select an advertisement format and customize your ad</li><li>Add your Branch Ad Link to your advertisement</li></ol><ul><li>If you chose app conversions App, copy and paste your [Branch ad link for deep linking]/using-branch/docs/facebook-app-install-ads#create-an-ad-link-for-deep-linking) into the <strong>Deep Link</strong> field.</li></ul><p><em>[Image: 1894]</em></p><ul><li>If you chose Website conversions, paste your Branch Ad link into the <strong>Website URL</strong> field.</li></ul><p><em>[Image: 1914]</em></p><ul><li>If you chose Website conversions and are using a full-screen Canvas, add your Branch Ad link as the <strong>Destination URL</strong> for your canvas advertisement components.</li></ul><ol start="7"><li>Complete the rest of the ad campaign setup.</li></ol><p>Some ad formats such as Carousel format can handle multiple deep links. To have link performance data on each image or component of the advertisement, create multiple Branch Ad links to be used in each part of the multiple link advertisement format. This format is useful if you want to drive customers to different content pieces or products.</p><h3 id="view-your-data" tabindex="-1">View Your Data <a class="header-anchor" href="#view-your-data" aria-label="Permalink to &quot;View Your Data&quot;">​</a></h3><p>The <a href="https://dashboard.branch.io/ads/analytics" target="_blank" rel="noreferrer">Ads Analytics Page</a> on the Branch dashboard provides an interactive time series graph and table to view the performance of your Ad campaigns.</p><p><em>[Image: 2596]</em></p><p>The table shows summary data on the performance of each Ad campaign. On the right top side of the table you can find a <strong>download button</strong> to retrieve the chart&#39;s content as a CSV file.</p><p><em>[Image: 2590]</em></p><div class="info custom-block"><p class="custom-block-title">Interacting with your data</p><p>Breakdown and compare aspects of your Ad campaigns&#39; performance by using the <code>Compare by +</code> button to add a parameter to split the data displayed data by.</p></div><p>Then use the <code>and +</code> button to refine the data displayed to gain deeper insight into the performance of your Ad campaigns.</p><h2 id="engagement-metrics" tabindex="-1">Engagement Metrics <a class="header-anchor" href="#engagement-metrics" aria-label="Permalink to &quot;Engagement Metrics&quot;">​</a></h2><p>You can view data for view-through engagement (<a href="https://www.facebook.com/business/help/1055388958765938" target="_blank" rel="noreferrer">engaged view</a>) conversion metrics for Facebook through Branch Dashboard reports and exports:</p><table tabindex="0"><thead><tr><th>Report/Export</th><th>Parameter</th><th>Value</th></tr></thead><tbody><tr><td>Dashboard Report</td><td><code>touch subtype</code></td><td><code>engaged_view</code></td></tr><tr><td>Dashboard Custom Exports</td><td>Column</td><td>Touch Subtype</td></tr><tr><td>Custom Exports API</td><td><code>fields</code></td><td><code>last_attributed_touch_data_tilde_touch_subtype</code></td></tr></tbody></table><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><p>We now have a dedicated <a href="./sources-of-discrepancies-between-facebook-and-branch.html">FAQ page for Facebook app ads</a>. If you are having any issues with app ads, please review the FAQ.</p><p>If you are having issues with web-only ads, you can check out the FAQ.</p>',93)])])}const m=a(n,[["render",r]]);export{u as __pageData,m as default};
